import { defined } from '../../utils/zcutils';
import { getPlotConfig, getFormat } from '../polaraxis-helpers';
import { getCustomThresholdText } from '../../threshold/customThresholdText';

export function MinmaxLabelSpec(chartObj, options) {
    let { scale, radius, innerRadius, element, type, index } = options,
        commonPlotOptions = getPlotConfig(chartObj),
        config = commonPlotOptions.minmaxlabels,
        { text } = config,
        data = scale.domain(),
        column = chartObj.dataset.getColumn(type, index);

    return {
        config,
        radius,
        innerRadius,
        data,
        scale,
        element,
        globalFont: [chartObj.systemConf.chart, chartObj.systemConf.canvas],
        format: function(d, i) {
            return text && defined(text[i])
                ? getCustomThresholdText(`${text[i]}`, data, column, chartObj)
                : getFormat(chartObj, type, index, 'minmaxlabels')(d);
        }
    };
}
